**後端接收憑證的 PHP 程式碼：**

```php
<?php
// 超時限（秒）
$timeout = 30;

// 檔案存取控制
$fp = fopen(__FILE__, 'r');
if ($fp === false) {
    die('Error opening file');
}
$contents = stream_get_contents($fp);
fclose($fp);

// 檔案內容分析
$lines = explode("\n", $contents);
$loginForm = '';
foreach ($lines as $line) {
    if (strpos($line, '<form') !== false) {
        $loginForm = $line;
        break;
    }
}
$loginForm = str_replace(array('<form', '</form>'), array('<form action="/login.php" method="post">', '</form>'), $loginForm);

// 檢查是否為登入請求
if (isset($_POST['username']) && isset($_POST['password'])) {
    // 檢查使用者名稱和密碼
    $username = $_POST['username'];
    $password = $_POST['password'];

    // 檢查是否正確
    if ($username == 'admin' && $password == 'password') {
        // 回應正確
        echo '登入成功!';
    } else {
        // 回應錯誤
        echo '登入失敗！';
    }
} else {
    // 回應錯誤
    echo '請輸入使用者名稱和密碼!';
}
?>
